def pre(i):
    # Input must be a pair (list_of_ints, k) where k is a positive integer
    if not isinstance(i, (list, tuple)) or len(i) != 2:
        return False
    lst, k = i
    if not isinstance(lst, list):
        return False
    if not all(isinstance(x, int) for x in lst):
        return False
    if not isinstance(k, int) or k <= 0:
        return False
    return True


def post(i, o):
    # Assumes pre(i) is True
    lst, k = i
    if 1 <= k <= len(lst):
        expected = sorted(lst)[k - 1]
    else:
        expected = None
    return o == expected
